func:
// Este nodo 'function' transforma cada fila de la consulta MSSQL
// en un mensaje que el nodo mysql-r2 puede usar para una inserción/actualización.

const mssqlRows = msg.payload; // msg.payload es un array de objetos de la consulta MSSQL

if (!Array.isArray(mssqlRows) || mssqlRows.length === 0) {
    node.warn("No se recibieron filas desde la consulta MSSQL.");
    return null; // Detiene el flujo si no hay datos
}

const mysqlMessages = []; // Array para almacenar los mensajes que se enviarán al nodo MySQL

// Cambiado a INSERT ... ON DUPLICATE KEY UPDATE
const insertSql = `
    INSERT INTO molienda (
        fechaindustrial, numero_pesada, GRUPO, caniero, nro_muestra, cania_bruta, 
        trash, trashReal, Polporciento, Brixporciento, Pureza, 
        Rendimiento, RendimientoReal, tipo_cania, fecha_pesada, 
        hora_pesada, fecha_salida, hora_salida, nromuestra2, 
        prepesada, usuario, tipo_contrato, transporte, 
        fletero, cosechero, finca, nombre_finca, patente, 
        observaciones, tara
    )
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON DUPLICATE KEY UPDATE 
        fechaindustrial = VALUES(fechaindustrial),
        nro_muestra = VALUES(nro_muestra),
        cania_bruta = VALUES(cania_bruta),
        trash = VALUES(trash),
        Polporciento = VALUES(Polporciento),
        Brixporciento = VALUES(Brixporciento),
        Pureza = VALUES(Pureza),
        Rendimiento = VALUES(Rendimiento),
        fecha_pesada = VALUES(fecha_pesada),
        hora_pesada = VALUES(hora_pesada)
`;

// Iterar sobre cada fila recibida de MSSQL
for (const row of mssqlRows) {
    // Mapear los nombres de columna de MSSQL a los parámetros de MySQL
    const fechaindustrial = row.fechaindustrial || '';
    const numero_pesada = row.numero_pesada || '';
    const GRUPO = row.GRUPO || '';
    const caniero = row.caniero || '';
    const nro_muestra = row.nro_muestra || '';
    const cania_bruta = row.cania_bruta || '';
    const trash = row.trash || '';
    const trashReal = row.trashReal || '';
    const Polporciento = row.Polporciento || '';
    const Brixporciento = row.Brixporciento || '';
    const Pureza = row.Pureza || '';
    const Rendimiento = row.Rendimiento || '';
    const RendimientoReal = row.RendimientoReal || '';
    const tipo_cania = row.tipo_cania || '';
    const fecha_pesada = row.fecha_pesada || '';
    const hora_pesada = row.hora_pesada || '';
    const fecha_salida = row.fecha_salida || '';
    const hora_salida = row.hora_salida || '';
    const nromuestra2 = row.nromuestra2 || '';
    const prepesada = row.prepesada || '';
    const usuario = row.usuario || '';
    const tipo_contrato = row.tipo_contrato || '';
    const transporte = row.transporte || '';
    const fletero = row.fletero || '';
    const cosechero = row.cosechero || '';
    const finca = row.finca || '';
    const nombre_finca = row.nombre_finca || '';
    const patente = row.patente || '';
    const observaciones = row.observaciones || '';
    const tara = row.tara || '';

    // Crear el array de parámetros en el ORDEN CORRECTO para la consulta preparada
    const params = [
        fechaindustrial, numero_pesada, GRUPO, caniero, nro_muestra, cania_bruta,
        trash, trashReal, Polporciento, Brixporciento, Pureza,
        Rendimiento, RendimientoReal, tipo_cania, fecha_pesada,
        hora_pesada, fecha_salida, hora_salida, nromuestra2,
        prepesada, usuario, tipo_contrato, transporte,
        fletero, cosechero, finca, nombre_finca, patente,
        observaciones, tara
    ];

    // Crear un nuevo mensaje para el nodo MySQL
    mysqlMessages.push({
        payload: params,
        topic: insertSql,
        // También puedes incluir la fila original para debugging
        _originalRow: row
    });
}

// Devolver los mensajes para el nodo MySQL
return [mysqlMessages];
